			header: 2
		}], // 1ć2 ēŗ§ę é¢
		[{
			list: "ordered"
		}, {
			list: "bullet"
		}], // ęåŗćę åŗåč”Ø
		[{
			script: "sub"
		}, {
			script: "super"
		}], // äøę /äøę 
		[{
			indent: "-1"
		}, {
			indent: "+1"
		}], // ē¼©čæ
		// [{'direction': 'rtl'}],                         // ęę¬ę¹å
		[{
			size: ["small", false, "large", "huge"]
		}], // å­ä½å¤§å°
		[{
			header: [1, 2, 3, 4, 5, 6, false]
		}], // ę é¢
		[{
			color: []
		}, {
			background: []
		}], // å­ä½é¢č²ćå­ä½čęÆé¢č²
		[{
			font: []
		}], // å­ä½ē§ē±»
		[{
			align: []
		}], // åÆ¹é½ę¹å¼
		["clean"], // ęøé¤ęę¬ę ¼å¼
		["link", "image", "video", "file", "audio", "table"], // é¾ę„ćå¾ēćč§é¢ćęä»¶ćęå„č”Øę ¼
	];
	var _EditorOption_ = function(page_this) {
		return {
			modules: {
				table: true,
				toolbar: {
					container: toolbarOptions,
					handlers: {
						image(value) {
							if (value) {
								page_this.openUploadByType("image");
							} else {
								this.quill.format("image", false);
							}
						},
						video(value) {
							if (value) {
								page_this.openUploadByType("video");
							} else {
								this.quill.format("video", false);
							}
						},
						file(value) {
							if (value) {
								page_this.openUploadByType("file");
							}
						},
						audio(value) {
							page_this.audioPlay()
						},
						table() {
							const quill = this.quill;
							const numberPattern = /^([1-9]|1\d|20)$/;
							page_this.$prompt("čÆ·č¾å„č”Øę ¼č”ę°ļ¼1-20ļ¼", "ęå„č”Øę ¼", {
								confirmButtonText: "äøäøę­„",
								cancelButtonText: "åę¶",
								inputValue: "3",
								inputPattern: numberPattern,
								inputErrorMessage: "čÆ·č¾å„ 1-20 ēę“ę°",
							}).then(({
								value: rowValue
							}) => {
								const rows = Number(rowValue);
								return page_this.$prompt("čÆ·č¾å„č”Øę ¼åę°ļ¼1-20ļ¼", "ęå„č”Øę ¼", {
									confirmButtonText: "ęå„",
									cancelButtonText: "åę¶",
									inputValue: "3",
									inputPattern: numberPattern,
									inputErrorMessage: "čÆ·č¾å„ 1-20 ēę“ę°",
								}).then(({
									value: colValue
								}) => ({
									rows,
									cols: Number(colValue),
								}));
							}).then(({
								rows,
								cols
							}) => {
								const tableModule = quill.getModule("table");
								if (tableModule && typeof tableModule.insertTable === "function") {
									tableModule.insertTable(rows, cols);
								} else {
									page_this.$message.error("č”Øę ¼ęØ”åęŖå č½½");
								}
							}).catch(() => {});
						},
					},
				},
			},
			placeholder: "čÆ·č¾å„ę­£ę",
			initButton: function () {
				//åØä½æēØēé”µé¢äø­åå§åęé®ę ·å¼
				const audio = document.querySelector(".ql-audio");
				if (audio) {
					audio.title = 'čÆ­čØęčÆ»'
					audio.style.cssText =
