				}
				const fileBtn = document.querySelector(".ql-file");
				if (fileBtn) {
					fileBtn.title = "äøä¼ ęä»¶";
				}
			},
		};
	};

	export default {
		props: {
			/*ē¼č¾åØēåå®¹*/
			value: {
				type: String
			},
			action: {
				type: String
			},
			/*å¾ēå¤§å°*/
			maxSize: {
				type: Number,
				default: 4000 //kb
			},
			myQuillEditor: {
				type: String
			}
		},

		components: {
			quillEditor
		},
		mounted() {
			this.editorOption.initButton();
		},
		data() {
			return {
				refname: this.myQuillEditor,
				content: this.value,
				quillUpdateImg: false, // ę ¹ę®å¾ēäøä¼ ē¶ęę„ē”®å®ęÆå¦ę¾ē¤ŗloadingåØē»ļ¼åå¼å§ęÆfalse,äøę¾ē¤ŗ
				uploadEmbedType: "image", // å½åäøä¼ åęå„ēåÆęę¬ē±»å
				editorOption: _EditorOption_(this),

				// serverUrl: `${base.url}sys/storage/uploadSwiper?token=${storage.get('token')}`, // čæéåä½ č¦äøä¼ ēå¾ēęå”åØå°å
				header: {
					// token: sessionStorage.token
					'Token': this.$storage.get("Token")
				} // ęēå¾ēęå”åØč¦ę±čÆ·ę±å¤“éč¦ętoken
			};
		},
		computed: {
			// č®”ē®å±ę§ē getter
			getActionUrl: function() {
				// return this.$base.url + this.action + "?token=" + this.$storage.get("token");
				return `/${this.$base.name}/` + this.action;
			},
			uploadAccept() {
				if (this.uploadEmbedType === "video") return "video/*";
				if (this.uploadEmbedType === "file") return "*/*";
				return "image/*";
			}
		},
		methods: {
			openUploadByType(type) {
				this.uploadEmbedType = type;
				// ē­å¾ DOM åę­„ accept ååęå¼éę©ę”ļ¼éæåę²æēØäøäøę¬”ē±»åéå¶
				this.$nextTick(() => {
					const uploadInput = document.querySelector("." + this.refname + "upload input");
					if (!uploadInput) return;
					uploadInput.setAttribute("accept", this.uploadAccept);
					uploadInput.click();
				});
			},
			audioPlay() {
				var div = document.createElement('div')
				div.innerHTML = this.value
				var text = div.textContent
				const utterance = new SpeechSynthesisUtterance();
				utterance.text = text;  
				utterance.lang = 'zh-CN';  
				utterance.rate = 1.5; // čÆ­éļ¼0.1-10ļ¼  
				utterance.pitch = 1.0; // é³č°ļ¼0-2ļ¼  
				utterance.volume = 1.0; // é³éļ¼0-1ļ¼  
				window.speechSynthesis.speak(utterance);  
			},
			onEditorBlur() {
				//å¤±å»ē¦ē¹äŗä»¶
			},
			onEditorFocus() {
				//č·å¾ē¦ē¹äŗä»¶
			},
			onEditorChange() {
				//åå®¹ę¹åäŗä»¶
				this.$emit("input", this.value);
			},
			// åÆęę¬å¾ēäøä¼ å
			beforeUpload(file) {
				if (!file || !file.type) {
					this.$message.error("ę ę³čÆå«ęä»¶ē±»å");
					return false;
				}
				if (this.uploadEmbedType === "file") {
					this.quillUpdateImg = true;
					return true;
				}
				const isVideoUpload = this.uploadEmbedType === "video";
				const isValidType = isVideoUpload ? file.type.startsWith("video/") : file.type.startsWith("image/");
				if (!isValidType) {
					this.$message.error(isVideoUpload ? "čÆ·éę©č§é¢ē±»åęä»¶" : "čÆ·éę©å¾ēē±»åęä»¶");
					return false;
				}
				// ę¾ē¤ŗloadingåØē»
				this.quillUpdateImg = true;
				return true;
			},

			uploadSuccess(res, file) {
				// resäøŗå¾ēęå”åØčæåēę°ę®
				// č·ååÆęę¬ē»ä»¶å®ä¾
				let quill = this.$refs[this.refname].quill;
				// å¦ęäøä¼ ęå
				if (res.code === 0) {
					// č·ååę ęåØä½ē½®
					const selection = quill.getSelection();
					let length = selection ? selection.index : quill.getLength();
					const fileUrl = this.$base.url + "upload/" + res.file;
					if (this.uploadEmbedType === "file") {
						const fileName = file && file.name ? file.name : (res.file || "äøč½½ęä»¶");
						const safeFileName = String(fileName).replace(/"/g, "&quot;");
						const safeFileUrl = String(fileUrl).replace(/"/g, "&quot;");
						quill.clipboard.dangerouslyPasteHTML(
							length,
							`<a href="${safeFileUrl}" download="${safeFileName}" target="_blank" rel="noopener noreferrer">${safeFileName}</a>`
						);
					} else {
						// ęęé®ē±»åęå„å¾ēęč§é¢
						quill.insertEmbed(length, this.uploadEmbedType, fileUrl);
					}
					// č°ę“åę å°ęå
					quill.setSelection(length + 1);
				} else {
					this.$message.error(this.uploadEmbedType === "video" ? "č§é¢ęå„å¤±č“„" : (this.uploadEmbedType === "file" ? "ęä»¶ęå„å¤±č“„" : "å¾ēęå„å¤±č“„"));
				}
				// loadingåØē»ę¶å¤±
				this.quillUpdateImg = false;
				this.uploadEmbedType = "image";
			},
			// åÆęę¬å¾ēäøä¼ å¤±č“„
			uploadError() {
				// loadingåØē»ę¶å¤±
				this.quillUpdateImg = false;
				this.$message.error(this.uploadEmbedType === "video" ? "č§é¢ęå„å¤±č“„" : (this.uploadEmbedType === "file" ? "ęä»¶ęå„å¤±č“„" : "å¾ēęå„å¤±č“„"));
				this.uploadEmbedType = "image";
			}
		}
	};
</script>

