<template>
	<div>
		<!-- äøä¼ ęä»¶ē»ä»¶ -->
		<el-upload :disabled="disabled" v-if="type==1" ref="upload" :action="getActionUrl" list-type="picture-card"
			:multiple="multiple" :limit="limit" :headers="myHeaders" :file-list="fileList" :on-exceed="handleExceed"
			:on-preview="handleUploadPreview" :on-remove="handleRemove" :on-success="handleUploadSuccess"
			:on-error="handleUploadErr" :timeout="600000">
			<i class="el-icon-plus"></i>
			<div slot="tip" class="el-upload__tip">{{tip}}</div>
		</el-upload>
		<el-upload :disabled="disabled" v-else-if="type==2||type==3" drag ref="upload" :action="getActionUrl" :multiple="multiple"
			:limit="limit" :accept="accept" :headers="myHeaders" :file-list="fileList" :on-exceed="handleExceed"
			:on-preview="handleUploadPreview" :on-remove="handleRemove" :on-success="handleUploadSuccess"
			:on-error="handleUploadErr" :timeout="600000">
			<i class="el-icon-upload"></i>
			<div class="el-upload__text">å°ęä»¶ęå°ę­¤å¤ļ¼ę<em>ē¹å»äøä¼ </em></div>
			<div slot="tip" class="el-upload__tip">{{tip}}</div>
		</el-upload>
		<el-upload :disabled="disabled" v-else drag ref="upload" :action="getActionUrl" :multiple="multiple"
			:limit="limit" :accept="accept" :headers="myHeaders" :file-list="fileList" :on-exceed="handleExceed"
			:on-preview="handleUploadPreview" :on-remove="handleRemove" :on-success="handleUploadSuccess"
			:on-error="handleUploadErr" :timeout="600000" :before-upload="handleBeforeUpload">
			<i class="el-icon-upload"></i>
			<div class="el-upload__text">å°ęä»¶ęå°ę­¤å¤ļ¼ę<em>ē¹å»äøä¼ </em></div>
			<div slot="tip" class="el-upload__tip">{{tip}}</div>
		</el-upload>
		<el-dialog :visible.sync="dialogVisible" size="tiny" append-to-body>
			<img width="100%" v-if="type==1" :src="dialogImageUrl" alt>
			<video width="100%" v-if="type==2" :src="dialogImageUrl" alt controls />
		</el-dialog>
	</div>
</template>
<script>
	import storage from "@/utils/storage";
	import base from "@/utils/base";
	export default {
		data() {
			return {
				// ę„ēå¤§å¾
				dialogVisible: false,
				// ę„ēå¤§å¾
				dialogImageUrl: "",
				// ē»ä»¶ęø²ęå¾ēēę°ē»å­ę®µļ¼ęē¹ę®ę ¼å¼č¦ę±
				fileList: [],
				fileUrlList: [],
				myHeaders: {}
			};
		},
		props: {
			tip: {
				type: String
			},
			action: {
				type: String
			},
			/*å¾ēå¤§å°*/
			limit: {
				type: Number,
				default: 3 //kb
			},
			multiple: {
				type: Boolean,
				default: false
			},
			fileUrls: {
				type: String
			},
			type: {
				type: Number,
				default: 1
			},
			disabled: {
				type: Boolean,
				default: false
			},
			accept: {
				type: String
			}
		},
		mounted() {
			this.init();
			this.myHeaders = {
				'Token': storage.get("Token")
			}
		},
		watch: {
			fileUrls: function(val, oldVal) {
				//   console.log("new: %s, old: %s", val, oldVal);
				this.init();
			}
		},
		computed: {
			// č®”ē®å±ę§ē getter
			getActionUrl: function() {
				// return base.url + this.action + "?token=" + storage.get("token");
				return `/${this.$base.name}/` + this.action;
			}
		},
		methods: {
			// åå§å
			init() {
				let that = this
				if (this.fileUrls) {
					this.fileUrlList = this.fileUrls.split(",w").length>1?this.fileUrls:this.fileUrls.split(',');
					let fileArray = [];
					this.fileUrlList.forEach(function(item, index) {
						var url = item;
						var name = that.type==4?'ę£ęµęä»¶':index;
						var file = {
							name: name,
							url: url
						};
						fileArray.push(file);
					});
					this.setFileList(fileArray);
				}
			},
			async handleBeforeUpload(file) {
				let that = this
				return new Promise(async(resolve, reject) => {
					const isLt3M = file.size / 1024 / 1024 < 3;
					if (!isLt3M) {
						that.$message.error('ęä»¶å¤§å°äøč½č¶čæ3MB!');
						reject()
						return false
					}
					if (file.type == 'video/mp4') {
						try {
							const duration = await that.getAudioDuration(file);
							if (duration > 60) { // 300ē§=5åé
								that.$message.error('č§é¢ę¶éæäøč½č¶čæ1åé!');
								reject()
								return false
							}
						} catch (error) {
							that.$message.error('č§é¢č§£ęå¤±č“„');
							reject()
							return false
						}
					}
					resolve()
				});
			},
			getAudioDuration(file) {
				return new Promise((resolve, reject) => {
					// åå»ŗäøäøŖ video åē“ ę„čÆ»åęä»¶
					const video = document.createElement('video');
					const url = URL.createObjectURL(file);
					video.src = url;
					
					// ē­å¾č§é¢åę°ę®å č½½å®ę
					video.onloadedmetadata = () => {
						resolve(video.duration)
						// čæéåÆä»„å¤ēä½ ēäøå”é»č¾ļ¼ęÆå¦å°ę¶éæå­åØęåéå°ęå”åØē­
						URL.revokeObjectURL(url); // éę¾ Object URL
					};
					
					// ē”®äæåØäøåéč¦č§é¢ę¶éę¾čµęŗ
					video.onerror = () => {
						reject()
						console.error('č§é¢å č½½å¤±č“„');
						URL.revokeObjectURL(url); // éę¾ Object URL
					};
				});
			},
			// äøä¼ ęä»¶ęååę§č”
			handleUploadSuccess(res, file, fileList) {
				if (res && res.code === 0) {
					fileList[fileList.length - 1]["url"] = "upload/" + file.response.file;
					this.setFileList(fileList);
					this.$emit("change", this.fileUrlList.join(","));
				} else {
					this.$message.error(res.msg);
				}
			},
			// å¾ēäøä¼ å¤±č“„
			handleUploadErr(err, file, fileList) {
				this.$message.error("ęä»¶äøä¼ å¤±č“„");
			},
			// ē§»é¤å¾ē
			handleRemove(file, fileList) {
				this.setFileList(fileList);
				this.$emit("change", this.fileUrlList.join(","));
			},
			// ę„ēå¤§å¾
			handleUploadPreview(file) {
				if(this.type>2){
					window.open(file.url)
					return false
				}
				this.dialogImageUrl = file.url;
				this.dialogVisible = true;
			},
			// éå¶å¾ēę°é
			handleExceed(files, fileList) {
				this.$message.warning(`ęå¤äøä¼ ${this.limit}å¼ ${this.type==1?'å¾ē':(this.type==2?'č§é¢':(this.type==3?'ęä»¶':'é³é¢'))}`);
			},
			// éę°åÆ¹fileListčæč”čµå¼
			setFileList(fileList) {
				var fileArray = [];
				var fileUrlArray = [];
				// ęäŗå¾ēäøęÆå¬å¼ēļ¼ęä»„éč¦ęŗåø¦tokenäæ”ęÆåęéę ”éŖ
				var token = storage.get("token");
				let _this = this;
				fileList.forEach(function(item, index) {
					var url = item.url.split("?")[0];
					if (!url.startsWith("http")) {
						url = _this.$base.url + url
					}
					var name = item.name;
					var file = {
						name: name,
						url: url + "?token=" + token
					};
					fileArray.push(file);
					fileUrlArray.push(url);
				});
				this.fileList = fileArray;
				this.fileUrlList = fileUrlArray;
			}
		}
	};
</script>
