		methods:{
			changeStatQuery(arr) {
				if(arr.length==1) {
					if(arr[0] == 'users'&&this.$storage.get("sessionTable")=='users') {
						return true
					}
				}
				let role = this.$storage.get('role')
				for(let x in arr) {
					if(arr[x] == role) {
						return true
					}
				}
				return false
			},
			getautohomeList() {
				let params = {
					page: 1,
					limit: 20,
				}
				params.order = 'desc'
				params.sort = 'liulan'
				this.$http({
					url: "autohome/page",
					method: "get",
					params: params
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.autohomeList = data.data.list;
						let div = document.getElementById('autohomeTable')
						var scrollTop = -1
						function move() {
							if (div){
								if(div.scrollTop==scrollTop){
									div.scrollTo({
										top: 0, 
										behavior: "smooth"
									});
									return false
								}
								scrollTop = div.scrollTop
								div.scrollTo({ 
									top: div.scrollTop + 40, 
									behavior: "smooth"
								});
							}
								
						}
						this.autohomeTimer = setInterval(move, 2000);
						div.addEventListener('mouseenter', e => {
							e.stopPropagation()
							clearInterval(this.autohomeTimer);
						})
						div.addEventListener('mouseleave', e => {
							e.stopPropagation()
							this.autohomeTimer = setInterval(move, 2000);
						})
					}
				});
			},
			backClick(){
				if(this.frontType==1) {
					window.location.href = `${this.$base.indexUrl}`
					return false
				}
				this.$router.replace({ path: "/" });
			},
