			filterTime(time) {
				const date = new Date(time)
				const Y = date.getFullYear()
				const M = date.getMonth() + 1 < 10 ? '0'+(date.getMonth()+1) : date.getMonth()+1 
				const D = date.getDate() < 10 ? '0' + date.getDate() : date.getDate()
			  
				const H = date.getHours() < 10 ? '0' + date.getHours() : date.getHours() // å°ę¶
				const I = date.getMinutes() < 10 ? '0' + date.getMinutes() : date.getMinutes() // åé
				const S = date.getSeconds() < 10 ? '0' + date.getSeconds() : date.getSeconds() // ē§
			  
				return `${Y}-${M}-${D} ${H}:${I}:${S}`
			},
