			getDataList() {
				this.dataListLoading = true;
				let params = {
					page: this.pageIndex,
					limit: this.pageSize,
					sort: 'id',
					order: 'desc',
				}
				if(this.searchForm.zixunbiaoti!='' && this.searchForm.zixunbiaoti!=undefined){
					params['zixunbiaoti'] = '%' + this.searchForm.zixunbiaoti + '%'
				}
				if(this.searchForm.zixunfenlei!='' && this.searchForm.zixunfenlei!=undefined){
					params['zixunfenlei'] = this.searchForm.zixunfenlei
				}
				let user = JSON.parse(this.$storage.getObj('userForm'))
				this.$http({
					url: "xingyezixun/page",
					method: "get",
					params: params
				}).then(({ data }) => {
					if (data && data.code === 0) {
						this.dataList = data.data.list;
						this.totalPage = data.data.total;
					} else {
						this.dataList = [];
						this.totalPage = 0;
					}
					this.dataListLoading = false;
				});
			},
			// ęÆé”µę°
			sizeChangeHandle(val) {
				this.pageSize = val;
				this.pageIndex = 1;
				this.getDataList();
			},
			// å½åé”µ
			currentChangeHandle(val) {
				this.pageIndex = val;
				this.getDataList();
			},
			// å¤é
			selectionChangeHandler(val) {
				this.dataListSelections = val;
			},
			// ę·»å /äæ®ę¹
			addOrUpdateHandler(id,type) {
				this.showFlag = false;
				this.addOrUpdateFlag = true;
				this.crossAddOrUpdateFlag = false;
				if(type!='info'&&type!='msg'){
					type = 'else';
				}
				this.$nextTick(() => {
					this.$refs.addOrUpdate.init(id,type );
				});
			},
			// ę„ēčÆč®ŗ
			disscussListHandler(id,type) {
				this.$router.push({path:'/discussxingyezixun',query:{refid:id}});
			},
			// å é¤
			async deleteHandler(id ) {
				var ids = id? [Number(id)]: this.dataListSelections.map(item => {
					return Number(item.id);
				});
				await this.$confirm(`ē”®å®čæč”[${id ? "å é¤" : "ę¹éå é¤"}]ęä½?`, "ęē¤ŗ", {
					confirmButtonText: "ē”®å®",
					cancelButtonText: "åę¶",
					type: "warning"
				}).then(async () => {
					await this.$http({
						url: "xingyezixun/delete",
						method: "post",
						data: ids
					}).then(async ({ data }) => {
						if (data && data.code === 0) {
							for(let x in ids){
								await this.$http.get('storeup/list',{params: {
									page: 1,
									limit: 100,
									refid: ids[x],
